namespace Alis.Reactive
{
    /// <summary>
    /// Immutable registration of a component in the reactive plan.
    /// Populated at view render time by each vertical slice's HtmlExtensions.
    /// Consumed by GatherResolver (HTTP serialization) and ValidationResolver (field enrichment).
    /// </summary>
    public sealed class ComponentRegistration
    {
        /// <summary>DOM element ID generated by IdGenerator from the model expression.</summary>
        public string ComponentId { get; }

        /// <summary>"native" or "fusion" — determines resolveRoot() strategy at runtime.</summary>
        public string Vendor { get; }

        /// <summary>Model property path (e.g., "AdmissionDate", "Address.Street") — key in ComponentsMap.</summary>
        public string BindingPath { get; }

        /// <summary>Dot-path from vendor root to the readable value (e.g., "value", "checked").</summary>
        public string ReadExpr { get; }

        /// <summary>Semantic component kind (e.g., "datepicker", "numerictextbox") — descriptive, not used for coercion.</summary>
        public string ComponentType { get; }

        /// <summary>
        /// Coercion type inferred from typeof(TProp) via CoercionTypes.InferFromType at registration.
        /// Flows to plan JSON → consumed by gather (daterange decomposition) and validation (field enrichment).
        /// Values: "string", "number", "boolean", "date", "array", "raw".
        /// </summary>
        public string CoerceAs { get; }

        public ComponentRegistration(string componentId, string vendor, string bindingPath, string readExpr, string componentType, string coerceAs)
        {
            ComponentId = componentId;
            Vendor = vendor;
            BindingPath = bindingPath;
            ReadExpr = readExpr;
            ComponentType = componentType;
            CoerceAs = coerceAs;
        }
    }
}
